262	func handleTapTab(_ parsed: ParsedOptions) throws -> Int32 {
263	    let target = try resolveTarget(from: parsed)
264	    guard let indexStr = parsed.options["--index"], let index = Int(indexStr) else {
265	        throw NativeError.invalidArguments("tap-tab requires --index <N>.")
266	    }
267	
268	    let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
269	    let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
270	
271	    try ensureAccessibilityTrusted()
272	    try activateTarget(target)
273	
274	    let appRoot = try accessibilityRootElement(for: target)
275	    let targetUdid = simulatorUdid(from: target)
276	    let searchRoot: UIElement = appRoot
277	
278	    guard let tabBar = findTabBarElement(in: searchRoot, simulatorUdid: targetUdid) else {
279	        throw NativeError.commandFailed("No tab bar found in the application UI. Ensure the app has a visible tab bar.")
280	    }
281	
282	    guard let frame = FrameAttribute(tabBar) else {
283	        throw NativeError.commandFailed("Tab bar element has no frame attribute.")
284	    }
285	
286	    let tabCount: Int
287	    if let tabCountStr = parsed.options["--tab-count"], let tc = Int(tabCountStr) {
288	        tabCount = tc
289	    } else {
290	        let children = Children(tabBar)
291	        tabCount = children.count
292	    }
293	
294	    guard tabCount > 0 else {
295	        throw NativeError.commandFailed("Tab bar has no children and --tab-count was not specified.")
296	    }
297	
298	    guard index >= 0 && index < tabCount else {
299	        throw NativeError.invalidArguments("Tab index \(index) is out of range. Valid range: 0..\(tabCount - 1)")
300	    }
301	
302	    if preDelay > 0 {
303	        Thread.sleep(forTimeInterval: preDelay)
304	    }
305	
306	    let actionableItems = actionableTabBarItems(in: tabBar)
307	    if actionableItems.count == tabCount {
308	        try performPrimaryAction(on: actionableItems[index])
309	        if postDelay > 0 {
310	            Thread.sleep(forTimeInterval: postDelay)
311	        }
312	        return 0
313	    }
314	
315	    if case .simulator = target,
316	       let contentRoot = simulatorContentRootElement(from: appRoot, udid: targetUdid) {
317	        let proxyItems = semanticProxyTabButtons(in: contentRoot, excluding: tabBar, expectedCount: tabCount)
318	        if proxyItems.count == tabCount {
319	            try performPrimaryAction(on: proxyItems[index])
320	            if postDelay > 0 {
321	                Thread.sleep(forTimeInterval: postDelay)
322	            }
323	            return 0
324	        }
325	    }
326	
327	    let tabWidth = frame.width / CGFloat(tabCount)
328	    let tapX = frame.origin.x + tabWidth * CGFloat(index) + tabWidth / 2.0
329	    let tapY = frame.origin.y + frame.height / 2.0
330	
331	    let backend = resolveInputBackend(for: target)
332	    switch backend {
333	    case .indigoHID(let client):
334	        guard let contentBounds = simulatorContentBounds(udid: targetUdid) else {
335	            throw NativeError.commandFailed("Cannot determine simulator content bounds for IndigoHID coordinate conversion. Ensure Simulator is running.")
336	        }
337	        let relX = Double(tapX) - Double(contentBounds.origin.x)
338	        let relY = Double(tapY) - Double(contentBounds.origin.y)
339	        if !client.tap(x: relX, y: relY) {
340	            throw NativeError.commandFailed("IndigoHID tap failed. The simulator may not be responding.")
341	        }
342	    case .cgevent:
343	        sendClick(at: CGPoint(x: tapX, y: tapY))
344	    }
345	
346	    if postDelay > 0 {
347	        Thread.sleep(forTimeInterval: postDelay)
348	    }
349	    return 0
350	}
