test("key_combo formats modifiers as comma-separated list", async () => {
  await withClient(async (client) => {
    const result = await client.callTool({
      name: "key_combo",
      arguments: {
        udid: "00000000-0000-0000-0000-000000000000",
        modifiers: [224, 225],
